previewCss:
.darma-loader-uiverse-crystal-bloom__container {
display: flex;
align-items: center;
justify-content: center;
}

.darma-loader-uiverse-crystal-bloom {
position: relative;
width: 200px;
height: 200px;
perspective: 800px;
}

.darma-loader-uiverse-crystal-bloom__crystal {
position: absolute;
top: 50%;
left: 50%;
width: 60px;
height: 60px;
opacity: 0;
transform-origin: bottom center;
transform: translate(-50%, -50%) rotateX(45deg) rotateZ(0deg);
animation: darma-loader-uiverse-crystal-bloom-spin 4s linear infinite, darma-loader-uiverse-crystal-bloom-emerge 2s ease-in-out infinite alternate,
darma-loader-uiverse-crystal-bloom-fadeIn 0.3s ease-out forwards;
border-radius: 10px;
visibility: hidden;
}

@keyframes darma-loader-uiverse-crystal-bloom-spin {
from {
transform: translate(-50%, -50%) rotateX(45deg) rotateZ(0deg);
}
to {
transform: translate(-50%, -50%) rotateX(45deg) rotateZ(360deg);
}
}

@keyframes darma-loader-uiverse-crystal-bloom-emerge {
0%,
100% {
transform: translate(-50%, -50%) scale(0.5);
opacity: 0;
}
50% {
transform: translate(-50%, -50%) scale(1);
opacity: 1;
}
}

@keyframes darma-loader-uiverse-crystal-bloom-fadeIn {
to {
visibility: visible;
opacity: 0.8;
}
}

.darma-loader-uiverse-crystal-bloom__crystal:nth-child(1) {
background: linear-gradient(45deg, #003366, #336699);
animation-delay: 0s;
}

.darma-loader-uiverse-crystal-bloom__crystal:nth-child(2) {
background: linear-gradient(45deg, #003399, #3366cc);
animation-delay: 0.3s;
}

.darma-loader-uiverse-crystal-bloom__crystal:nth-child(3) {
background: linear-gradient(45deg, #0066cc, #3399ff);
animation-delay: 0.6s;
}

.darma-loader-uiverse-crystal-bloom__crystal:nth-child(4) {
background: linear-gradient(45deg, #0099ff, #66ccff);
animation-delay: 0.9s;
}

.darma-loader-uiverse-crystal-bloom__crystal:nth-child(5) {
background: linear-gradient(45deg, #33ccff, #99ccff);
animation-delay: 1.2s;
}

.darma-loader-uiverse-crystal-bloom__crystal:nth-child(6) {
background: linear-gradient(45deg, #66ffff, #ccffff);
animation-delay: 1.5s;
}

